+      const hooks = (
+        window as typeof globalThis & {
+          __summarizeTestHooks?: { forceRenderSlides?: () => number }
+        }
+      ).__summarizeTestHooks
+      return hooks?.forceRenderSlides?.() ?? 0
+    })
